var prompt = 'You are a professional transcription and summarization specialist. Analyze and summarize the following audio content description into a structured document.

';
prompt += 'AUDIO CONTENT:
' + $.input.audioDescription + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Create a structured summary with title, key points, action items, and detailed notes
';
prompt += '- Extract any names, dates, decisions, and commitments mentioned
';
prompt += '- Organize information chronologically if applicable
';
prompt += '- Highlight important quotes or statements
';
prompt += '- Create a brief executive summary (2-3 sentences)

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "title": "Document title",
';
prompt += '  "executiveSummary": "2-3 sentence overview",
';
prompt += '  "keyPoints": ["point1", "point2"],
';
prompt += '  "actionItems": [{ "item": "...", "assignee": "...", "deadline": "..." }],
';
prompt += '  "participants": ["person1"],
';
prompt += '  "decisions": ["decision1"],
';
prompt += '  "detailedNotes": "Full structured notes in markdown",
';
prompt += '  "tags": ["tag1"]
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiSummarize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Transcription Summary', executiveSummary: '', keyPoints: [], actionItems: [], participants: [], decisions: [], detailedNotes: raw, tags: [] }; }

var ai = $.steps.parseAI.output;
var now = new Date();
var dateStr = now.toISOString().split('T')[0];
var doc = '# ' + (ai.title || 'Transcription Summary') + '\n\n';
doc += '**Date:** ' + dateStr + '\n\n';
doc += '## Executive Summary\n' + (ai.executiveSummary || '') + '\n\n';
if (ai.participants && ai.participants.length > 0) {
  doc += '## Participants\n' + ai.participants.map(function(p) { return '- ' + p; }).join('\n') + '\n\n';
}
doc += '## Key Points\n';
(ai.keyPoints || []).forEach(function(p) { doc += '- ' + p + '\n'; });
doc += '\n';
if (ai.decisions && ai.decisions.length > 0) {
  doc += '## Decisions\n';
  ai.decisions.forEach(function(d) { doc += '- ' + d + '\n'; });
  doc += '\n';
}
if (ai.actionItems && ai.actionItems.length > 0) {
  doc += '## Action Items\n';
  ai.actionItems.forEach(function(a) {
    doc += '- [ ] ' + a.item;
    if (a.assignee) doc += ' (' + a.assignee + ')';
    if (a.deadline) doc += ' - Due: ' + a.deadline;
    doc += '\n';
  });
  doc += '\n';
}
doc += '## Detailed Notes\n' + (ai.detailedNotes || '') + '\n\n';
doc += '---\n*Generated with Claude AI via One CLI*\n';
var fileName = (ai.title || 'Summary').replace(/[^a-zA-Z0-9 -]/g, '').slice(0, 50) + ' - ' + dateStr + '.md';
return { document: doc, fileName: fileName, dateStr: dateStr, title: ai.title || 'Transcription Summary' };

var ai = $.steps.parseAI.output;
var doc = $.steps.buildDocument.output;
var html = '<h2>Transcription Summary Ready</h2>';
html += '<p><strong>Title:</strong> ' + doc.title + '</p>';
html += '<p><strong>Date:</strong> ' + doc.dateStr + '</p>';
html += '<hr>';
html += '<h3>Executive Summary</h3>';
html += '<p>' + (ai.executiveSummary || 'No summary available') + '</p>';
if (ai.keyPoints && ai.keyPoints.length > 0) {
  html += '<h3>Key Points</h3><ul>';
  ai.keyPoints.forEach(function(p) { html += '<li>' + p + '</li>'; });
  html += '</ul>';
}
if (ai.actionItems && ai.actionItems.length > 0) {
  html += '<h3>Action Items</h3><ul>';
  ai.actionItems.forEach(function(a) {
    html += '<li>' + a.item;
    if (a.assignee) html += ' <em>(' + a.assignee + ')</em>';
    html += '</li>';
  });
  html += '</ul>';
}
html += '<hr><p><small>Full document saved to Google Drive: ' + doc.fileName + '</small></p>';
var subject = 'Transcription Ready: ' + doc.title;
return { subject: subject, htmlBody: html.slice(0, 1900) };
